--
-- Name: v_user_catalog; Type: VIEW; Schema: public; Owner: tracker
--

CREATE VIEW public.v_user_catalog AS
 SELECT ue.id AS entry_id,
    ue.user_id,
    u.username,
    m.id AS media_id,
    m.type,
    m.title,
    m.title_original,
    m.year,
    m.genres,
    m.cover_url,
    m.duration,
    m.country,
    m.network,
    m.external_score,
    m.platform AS media_platform,
    ue.status,
    ue.progress,
    ue.score,
    ue.rating_label,
    ue.notes,
    ue.platform AS watched_on,
    ue.started_at,
    ue.completed_at,
    ue.updated_at
   FROM ((public.user_entries ue
     JOIN public.users u ON ((u.id = ue.user_id)))
     JOIN public.media m ON ((m.id = ue.media_id)));


ALTER VIEW public.v_user_catalog OWNER TO tracker;

